import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Song {
  title: string;
  artist: string;
}

export interface Insight {
  content: string;
}

import { Song } from './types';

export const SONGS_PLAYLIST: Song[] = [
  { title: "Зајди, зајди, јасно сонце", artist: "Александар Сариевски" },
  { title: "Билјана платно белеше", artist: "Никола Бадев" },
  { title: "Македонско девојче", artist: "Јонуз Локна" },
  { title: "Јовано, Јованке", artist: "Васка Илиева" },
  { title: "Елено ќерко", artist: "Есма Реџепова" },
  { title: "Кажи, кажи либе Стано", artist: "Кирил Манчевски" },
  { title: "Море сокол пие", artist: "Добри Ставревски" }
];

export const COLORS = {
  background: 'bg-[#0f172a]', // Charcoal
  surface: 'bg-[#1e293b]', // Dark blue-gray
  accent: 'text-[#ecfdf5]', // Creamy off-white
  muted: 'text-[#94a3b8]', // Slate blue-gray
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMusicInsight(songTitle: string, artistName: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Обезбеди кратко, културно и достоинствено објаснување (максимум 2 реченици) на македонски јазик за значењето или историјата на народната песна "${songTitle}" од ${artistName}. Биди сериозен и почитуван кон традицијата.`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      },
    });
    return response.text || "Зачувување на македонскиот бит преку звуците на изворната песна.";
  } catch (error) {
    console.error("Error fetching insight:", error);
    return "Музика која ја раскажува историјата на македонскиот народ.";
  }
}

import React from 'react';
import { Play, Square } from 'lucide-react';

interface PlayerControlsProps {
  isPlaying: boolean;
  togglePlay: () => void;
}

const PlayerControls: React.FC<PlayerControlsProps> = ({ isPlaying, togglePlay }) => {
  return (
    <button
      onClick={togglePlay}
      className="group relative flex items-center justify-center w-24 h-24 rounded-full border border-stone-700 bg-transparent hover:bg-stone-800 transition-all duration-500 focus:outline-none"
      aria-label={isPlaying ? "Стопирај" : "Слушај во живо"}
    >
      <div className="absolute inset-0 rounded-full border border-stone-600 animate-pulse opacity-20 group-hover:opacity-40"></div>
      {isPlaying ? (
        <Square className="w-8 h-8 text-white fill-current" />
      ) : (
        <Play className="w-8 h-8 text-white fill-current ml-1" />
      )}
    </button>
  );
};

export default PlayerControls;

import React, { useEffect, useState } from 'react';

const Visualizer: React.FC<{ active: boolean }> = ({ active }) => {
  const [bars, setBars] = useState<number[]>(Array(12).fill(2));

  useEffect(() => {
    let interval: any;
    if (active) {
      interval = setInterval(() => {
        setBars(prev => prev.map(() => Math.floor(Math.random() * 12) + 2));
      }, 150);
    } else {
      setBars(Array(12).fill(2));
    }
    return () => clearInterval(interval);
  }, [active]);

  return (
    <div className="flex items-end justify-center gap-1 h-6">
      {bars.map((height, i) => (
        <div
          key={i}
          className="w-1 bg-stone-500/40 transition-all duration-300"
          style={{ height: `${height}px` }}
        />
      ))}
    </div>
  );
};

export default Visualizer;

import React, { useState, useEffect, useCallback } from 'react';
import { Radio } from 'lucide-react';
import PlayerControls from './components/PlayerControls';
import Visualizer from './components/Visualizer';
import { SONGS_PLAYLIST } from './constants';
import { getMusicInsight } from './services/geminiService';
import { Song } from './types';

const App: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSong, setCurrentSong] = useState<Song>(SONGS_PLAYLIST[0]);
  const [insight, setInsight] = useState<string>("Поврзување со корените преку традиционален звук.");
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);

  // Simulate a radio station cycling through songs
  const cycleSongs = useCallback(() => {
    const nextIndex = (SONGS_PLAYLIST.findIndex(s => s.title === currentSong.title) + 1) % SONGS_PLAYLIST.length;
    setCurrentSong(SONGS_PLAYLIST[nextIndex]);
  }, [currentSong]);

  useEffect(() => {
    const timer = setInterval(() => {
      if (isPlaying) {
        cycleSongs();
      }
    }, 45000); // Cycle every 45 seconds for demo purposes
    return () => clearInterval(timer);
  }, [isPlaying, cycleSongs]);

  // Fetch cultural insight whenever the song changes
  useEffect(() => {
    const fetchInsight = async () => {
      setIsLoadingInsight(true);
      const newInsight = await getMusicInsight(currentSong.title, currentSong.artist);
      setInsight(newInsight);
      setIsLoadingInsight(false);
    };
    fetchInsight();
  }, [currentSong]);

  const togglePlay = () => setIsPlaying(!isPlaying);

  return (
    <div className="min-h-screen flex flex-col items-center justify-between stone-gradient overflow-hidden px-6">

      {/* Header / Logo Section */}
      <header className="pt-20 text-center w-full max-w-4xl">
        <div className="flex justify-center mb-6">
          <div className="w-12 h-[1px] bg-stone-700 self-center"></div>
          <Radio className="mx-6 w-5 h-5 text-stone-500" />
          <div className="w-12 h-[1px] bg-stone-700 self-center"></div>
        </div>
        <h1 className="font-serif text-4xl md:text-6xl lg:text-7xl font-light tracking-wide text-stone-100 mb-4">
          Македонско народно радио
        </h1>
        <p className="font-sans text-sm md:text-base uppercase tracking-[0.3em] text-stone-400 font-medium">
          Кој пее, зло не мисли
        </p>
      </header>

      {/* Main Interaction Section */}
      <main className="flex flex-col items-center justify-center flex-grow py-12 w-full max-w-2xl text-center">

        <div className="mb-12">
          <PlayerControls isPlaying={isPlaying} togglePlay={togglePlay} />
        </div>

        {/* Now Playing Section */}
        <section className={`transition-opacity duration-1000 ${isPlaying ? 'opacity-100' : 'opacity-40'}`}>
          <div className="space-y-2 mb-8">
            <h2 className="text-stone-400 text-xs uppercase tracking-widest mb-4">
              {isPlaying ? "Во живо" : "Радиото е во прекин"}
            </h2>
            <p className="font-serif text-2xl md:text-3xl text-stone-200">
              {currentSong.title}
            </p>
            <p className="text-stone-500 font-light text-lg">
              {currentSong.artist}
            </p>
          </div>

          <Visualizer active={isPlaying} />

          {/* Cultural Context (Insight) */}
          <div className="mt-12 max-w-md mx-auto h-24">
            <div className={`transition-all duration-700 ${isLoadingInsight ? 'opacity-30 blur-sm' : 'opacity-100'}`}>
              <p className="italic text-stone-400 font-light text-sm leading-relaxed border-t border-stone-800 pt-6">
                "{insight}"
              </p>
            </div>
          </div>
        </section>
      </main>

      {/* About Section */}
      <section className="mb-20 text-center max-w-md px-4">
        <p className="text-stone-400 text-sm leading-relaxed font-light">
          Онлајн радио со македонска народна музика, достапно 24/7 ширум светот. Нашата мисија е зачувување и промоција на богатото македонско фолклорно наследство.
        </p>
      </section>

      {/* Footer */}
      <footer className="pb-10 w-full text-center">
        <div className="w-full h-[1px] bg-stone-800 mb-8"></div>
        <p className="text-[10px] uppercase tracking-[0.2em] text-stone-600">
          &copy; {new Date().getFullYear()} • Македонско народно радио • Сите права се задржани
        </p>
      </footer>

      {/* Background Decorative Element */}
      <div className="fixed -bottom-48 -right-48 w-96 h-96 bg-stone-800/10 rounded-full blur-[100px] pointer-events-none"></div>
      <div className="fixed -top-48 -left-48 w-96 h-96 bg-green-900/5 rounded-full blur-[100px] pointer-events-none"></div>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMusicInsight(songTitle: string, artistName: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ти си уредник на "Македонско народно радио". Напиши една кратка, инспиративна реченица на македонски јазик која објаснува зошто оваа песна ("${songTitle}" од ${artistName}) е важен дел од нашата радио програма и како таа го чува македонскиот идентитет. Биди поетски расположен, достоинствен и сериозен. Избегнувај суви факти, фокусирај се на емоцијата и мисијата на радиото.`,
      config: {
        temperature: 0.8,
        topP: 0.95,
      },
    });
    return response.text || "Оваа песна е столбот на нашата традиција, која ја пренесуваме на идните генерации.";
  } catch (error) {
    console.error("Error fetching insight:", error);
