import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Radio, Info, Volume2, VolumeX } from 'lucide-react';
import PlayerControls from './components/PlayerControls';
import Visualizer from './components/Visualizer';
import { SONGS_PLAYLIST } from './constants';
import { getMusicInsight } from './services/geminiService';
import { Song } from './types';

const STREAM_URL = "https://radio.dukahosting.com/8004/stream";

const App: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [isMuted, setIsMuted] = useState(false);
  const [currentSong, setCurrentSong] = useState<Song>(SONGS_PLAYLIST[0]);
  const [insight, setInsight] = useState<string>("Гласот на традицијата одекнува низ етерот.");
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(STREAM_URL);
    audioRef.current.crossOrigin = "anonymous";

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
        audioRef.current = null;
      }
    };
  }, []);

  // Handle Playback
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPlaying) {
      // For live streams, it's better to reload the source to ensure we are at the live "edge"
      audioRef.current.src = STREAM_URL;
      audioRef.current.load();
      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.error("Playback failed:", error);
          setIsPlaying(false);
        });
      }
    } else {
      audioRef.current.pause();
      // Clear src to stop buffering in the background
      audioRef.current.src = "";
    }
  }, [isPlaying]);

  // Handle Volume
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  // Simulate a playlist for cultural context
  const cycleSongs = useCallback(() => {
    const nextIndex = (SONGS_PLAYLIST.findIndex(s => s.title === currentSong.title) + 1) % SONGS_PLAYLIST.length;
    setCurrentSong(SONGS_PLAYLIST[nextIndex]);
  }, [currentSong]);

  useEffect(() => {
    let timer: any;
    if (isPlaying) {
      timer = setInterval(() => {
        cycleSongs();
      }, 60000); // Cycle every minute to provide fresh cultural insights
    }
    return () => clearInterval(timer);
  }, [isPlaying, cycleSongs]);

  // Fetch cultural insight whenever the "current song" (context) changes
  useEffect(() => {
    const fetchInsight = async () => {
      setIsLoadingInsight(true);
      const newInsight = await getMusicInsight(currentSong.title, currentSong.artist);
      setInsight(newInsight);
      setIsLoadingInsight(false);
    };
    fetchInsight();
  }, [currentSong]);

  const togglePlay = () => setIsPlaying(!isPlaying);
  const toggleMute = () => setIsMuted(!isMuted);

  return (
    <div className="min-h-screen flex flex-col items-center justify-between stone-gradient overflow-hidden px-6 selection:bg-stone-500/30">

      {/* Header / Logo Section */}
      <header className="pt-16 text-center w-full max-w-4xl z-10">
        <div className="flex justify-center mb-6">
          <div className="w-12 h-[1px] bg-stone-700 self-center"></div>
          <Radio className="mx-6 w-5 h-5 text-stone-500" />
          <div className="w-12 h-[1px] bg-stone-700 self-center"></div>
        </div>
        <h1 className="font-serif text-4xl md:text-6xl lg:text-7xl font-light tracking-wide text-stone-100 mb-4 drop-shadow-sm">
          Македонско народно радио
        </h1>
        <p className="font-sans text-xs md:text-sm uppercase tracking-[0.3em] text-stone-400 font-medium opacity-80">
          Кој пее, зло не мисли
        </p>
      </header>

      {/* Main Interaction Section */}
      <main className="flex flex-col items-center justify-center flex-grow py-8 w-full max-w-2xl text-center z-10">

        <div className="mb-10 flex flex-col items-center gap-6">
          <PlayerControls isPlaying={isPlaying} togglePlay={togglePlay} />

          {/* Volume Control */}
          <div className="flex items-center gap-3 bg-stone-900/40 backdrop-blur-sm px-4 py-2 rounded-full border border-stone-800/50">
            <button onClick={toggleMute} className="text-stone-500 hover:text-stone-300 transition-colors">
              {isMuted || volume === 0 ? <VolumeX size={16} /> : <Volume2 size={16} />}
            </button>
            <input 
              type="range" 
              min="0" 
              max="1" 
              step="0.01" 
              value={isMuted ? 0 : volume} 
              onChange={(e) => {
                setVolume(parseFloat(e.target.value));
                if (isMuted) setIsMuted(false);
              }}
              className="w-24 h-1 bg-stone-700 rounded-lg appearance-none cursor-pointer accent-stone-400"
            />
          </div>
        </div>

        {/* Status and Visualizer */}
        <section className={`transition-all duration-1000 w-full ${isPlaying ? 'opacity-100 transform translate-y-0' : 'opacity-40 transform translate-y-2'}`}>
          <div className="space-y-2 mb-8">
            <h2 className="text-stone-500 text-[10px] uppercase tracking-[0.25em] mb-4 flex items-center justify-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isPlaying ? 'bg-red-500 animate-pulse' : 'bg-stone-600'}`}></span>
              {isPlaying ? "Во живо на етерот" : "Радиото е во прекин"}
            </h2>
            <div className="min-h-[80px]">
              <p className="font-serif text-2xl md:text-4xl text-stone-200 leading-tight transition-all duration-500">
                {isPlaying ? currentSong.title : "Слушајте во живо"}
              </p>
              <p className="text-stone-500 font-light text-base md:text-xl mt-2">
                {isPlaying ? currentSong.artist : "Македонска народна музика"}
              </p>
            </div>
          </div>

          <Visualizer active={isPlaying} />

          {/* Editor's Note (Insight) - Only meaningful when playing */}
          <div className="mt-10 max-w-lg mx-auto min-h-[120px] flex flex-col items-center">
            <div className={`transition-all duration-700 ${isLoadingInsight ? 'opacity-20 blur-sm' : 'opacity-100'} ${!isPlaying && 'grayscale opacity-20'}`}>
              <span className="text-[10px] uppercase tracking-widest text-stone-600 mb-3 block tracking-[0.3em]">Белешка од уредникот</span>
              <p className="italic text-stone-400 font-light text-sm md:text-base leading-relaxed relative px-8 max-w-md">
                <span className="absolute left-0 top-0 text-3xl text-stone-800 font-serif leading-none">“</span>
                {insight}
                <span className="absolute right-0 bottom-0 text-3xl text-stone-800 font-serif leading-none">”</span>
              </p>
            </div>
          </div>
        </section>
      </main>

      {/* About Section */}
