import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getThemeInsight(themeTitle: string, themeDescription: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ти си уредник на "Македонско народно радио". Моментално во етерот се слуша музика со мотив: "${themeTitle}". 
      Опис на мотивот: "${themeDescription}". 
      Напиши една кратка, поетска и достоинствена реченица (максимум 20 зборови) на македонски јазик која ќе го објасни значењето на овој мелос за македонската култура. 
      Биди емотивен, избегнувај суви факти. Обрати се кон слушателот како некој што ја споделува душата на традицијата.`,
      config: {
        temperature: 0.8,
        topP: 0.95,
      },
    });
    return response.text || "Музика која го чува македонскиот бит низ вековите.";
  } catch (error) {
    console.error("Error fetching insight:", error);
    return "Традицијата е жива додека ја пееме со срце.";
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
