import { getThemeInsight } from './services/geminiService';

const STREAM_URL = "https://radio.dukahosting.com/8004/stream";

const App: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [isMuted, setIsMuted] = useState(false);
  const [currentTheme, setCurrentTheme] = useState<CulturalTheme>(CULTURAL_THEMES[0]);
  const [insight, setInsight] = useState<string>("Гласот на традицијата одекнува низ етерот.");
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Initialize Audio
  useEffect(() => {
    audioRef.current = new Audio(STREAM_URL);
    audioRef.current.crossOrigin = "anonymous";

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.src = "";
        audioRef.current = null;
      }
    };
  }, []);

  // Handle Playback
  useEffect(() => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.src = STREAM_URL;
      audioRef.current.load();
      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.error("Playback failed:", error);
          setIsPlaying(false);
        });
      }
    } else {
      audioRef.current.pause();
      audioRef.current.src = "";
    }
  }, [isPlaying]);

  // Handle Volume
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = isMuted ? 0 : volume;
    }
  }, [volume, isMuted]);

  // Cycle cultural themes to provide fresh context during listening
  const cycleThemes = useCallback(() => {
    const nextIndex = (CULTURAL_THEMES.findIndex(t => t.id === currentTheme.id) + 1) % CULTURAL_THEMES.length;
    setCurrentTheme(CULTURAL_THEMES[nextIndex]);
  }, [currentTheme]);

  useEffect(() => {
    let timer: any;
    if (isPlaying) {
      timer = setInterval(() => {
        cycleThemes();
      }, 90000); // Cycle themes every 90 seconds
    }
    return () => clearInterval(timer);
  }, [isPlaying, cycleThemes]);

  // Fetch cultural insight whenever the theme changes
  useEffect(() => {
    const fetchInsight = async () => {
      setIsLoadingInsight(true);
      const newInsight = await getThemeInsight(currentTheme.title, currentTheme.description);
      setInsight(newInsight);
      setIsLoadingInsight(false);
    };
    fetchInsight();
  }, [currentTheme]);

  const togglePlay = () => setIsPlaying(!isPlaying);
  const toggleMute = () => setIsMuted(!isMuted);

