export type Language = 'mk' | 'en';

import { GoogleGenAI } from "@google/genai";
import { Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMusicInsight(songTitle: string, artistName: string, lang: Language): Promise<string> {
  const languageName = lang === 'mk' ? 'Macedonian' : 'English';
  const prompt = lang === 'mk' 
    ? `Ти си уредник на "Македонско народно радио". Напиши една кратка, инспиративна реченица на македонски јазик која објаснува зошто оваа песна ("${songTitle}" од ${artistName}) е важен дел од нашата радио програма и како таа го чува македонскиот идентитет. Биди поетски расположен, достоинствен и сериозен. Избегнувај суви факти, фокусирај се на емоцијата и мисијата на радиото. Максимум 20 зборови.`
    : `You are the editor of "Macedonian Folk Radio". Write a short, inspiring sentence in English explaining why this song ("${songTitle}" by ${artistName}) is an important part of our radio program and how it preserves Macedonian identity. Be poetic, dignified, and serious. Avoid dry facts, focus on the emotion and the radio's mission. Maximum 20 words.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.8,
        topP: 0.95,
      },
    });

    return response.text?.trim() || (lang === 'mk' ? "Оваа песна е столбот на нашата традиција." : "This song is the pillar of our tradition.");
  } catch (error) {
    console.error("Error fetching insight:", error);
    return lang === 'mk' 
      ? "Музика која го грее срцето и го чува македонскиот бит низ вековите." 
      : "Music that warms the heart and preserves the Macedonian beat through the centuries.";
  }
}

