import { Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Simple in-memory cache to prevent repeated calls for the same song/language
const insightCache: Record<string, string> = {};

export async function getMusicInsight(songTitle: string, artistName: string, lang: Language): Promise<string> {
  const cacheKey = `${songTitle}-${artistName}-${lang}`;

  if (insightCache[cacheKey]) {
    return insightCache[cacheKey];
  }

  const prompt = lang === 'mk' 
    ? `Ти си уредник на "Македонско народно радио". Напиши една кратка, инспиративна реченица на македонски јазик која објаснува зошто оваа песна ("${songTitle}" од ${artistName}) е важен дел од нашата радио програма и како таа го чува македонскиот идентитет. Биди поетски расположен, достоинствен и сериозен. Максимум 20 зборови.`
    : `You are the editor of "Macedonian Traditional & Folk Radio". Write a short, inspiring sentence in English explaining why this song ("${songTitle}" by ${artistName}) is an important part of our radio program and how it preserves Macedonian identity. Be poetic, dignified, and serious. Maximum 20 words.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
